import type { Metadata } from 'next';
import { MarketingPage } from '@/components/marketing/MarketingPage';
import { JsonLd } from '@/components/seo/JsonLd';
import { getNpmVersion } from '@/lib/npm-version';

const title = 'Code Insights — Understand Your AI Coding Sessions';
const description =
  'Parse sessions from Claude Code, Cursor, Codex, Copilot, and VS Code Copilot Chat. Extract decisions and learnings. Track patterns. All local, all yours.';

export const metadata: Metadata = {
  title,
  description,
  keywords: [
    'AI coding analytics',
    'Claude Code',
    'Cursor',
    'Codex CLI',
    'Copilot CLI',
    'session analytics',
    'local-first',
    'developer tools',
    'CLI',
  ],
  openGraph: {
    title,
    description,
    url: 'https://code-insights.app',
  },
  twitter: {
    title,
    description,
  },
  alternates: {
    canonical: 'https://code-insights.app',
  },
};

function buildJsonLd(version: string | null) {
  return {
    '@context': 'https://schema.org',
    '@type': 'SoftwareApplication',
    name: 'Code Insights',
    description,
    url: 'https://code-insights.app',
    applicationCategory: 'DeveloperApplication',
    operatingSystem: 'macOS, Linux, Windows',
    ...(version && { softwareVersion: version }),
    offers: {
      '@type': 'Offer',
      price: '0',
      priceCurrency: 'USD',
    },
    license: 'https://opensource.org/licenses/MIT',
    isAccessibleForFree: true,
    installUrl: 'https://www.npmjs.com/package/@code-insights/cli',
    softwareRequirements: 'Node.js 18+',
    codeRepository: 'https://github.com/melagiri/code-insights',
    author: {
      '@type': 'Person',
      name: 'Srikanth Rao',
      url: 'https://melagiri.dev',
    },
  };
}

const organizationJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'Organization',
  name: 'Code Insights',
  url: 'https://code-insights.app',
  logo: 'https://code-insights.app/icon.svg',
  sameAs: [
    'https://github.com/melagiri/code-insights',
    'https://www.npmjs.com/package/@code-insights/cli',
  ],
  founder: {
    '@type': 'Person',
    name: 'Srikanth Rao',
    url: 'https://melagiri.dev',
  },
};

const faqJsonLd = {
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  mainEntity: [
    {
      '@type': 'Question',
      name: 'What AI coding tools does Code Insights support?',
      acceptedAnswer: {
        '@type': 'Answer',
        text: 'Code Insights supports Claude Code, Cursor, Codex CLI, Copilot CLI, and VS Code Copilot Chat. All tools are auto-detected during setup.',
      },
    },
    {
      '@type': 'Question',
      name: 'Is my data sent to the cloud?',
      acceptedAnswer: {
        '@type': 'Answer',
        text: 'No. Code Insights is fully local-first. All session data is stored in a SQLite database on your machine at ~/.code-insights/data.db. No accounts, no cloud services, no data ever leaves your device.',
      },
    },
    {
      '@type': 'Question',
      name: 'How do I install Code Insights?',
      acceptedAnswer: {
        '@type': 'Answer',
        text: 'Run "npm install -g @code-insights/cli" to install globally. Then run "code-insights init" to auto-detect your AI tools and set up the database. No configuration files or API keys needed.',
      },
    },
    {
      '@type': 'Question',
      name: 'Is Code Insights free?',
      acceptedAnswer: {
        '@type': 'Answer',
        text: 'Yes. Code Insights is free and open-source under the MIT license. The entire stack (CLI, dashboard, and server) is available on GitHub.',
      },
    },
    {
      '@type': 'Question',
      name: 'What insights can Code Insights extract from my sessions?',
      acceptedAnswer: {
        '@type': 'Answer',
        text: 'Code Insights extracts decisions, learnings, techniques, and patterns from your AI coding sessions using optional LLM analysis. It also provides terminal analytics with cost breakdowns, model usage stats, and per-project activity summaries.',
      },
    },
  ],
};

export default async function Page() {
  const version = await getNpmVersion();
  return (
    <>
      <JsonLd data={buildJsonLd(version)} />
      <JsonLd data={organizationJsonLd} />
      <JsonLd data={faqJsonLd} />
      <MarketingPage version={version} />
    </>
  );
}

