'use client';

import { useRef } from 'react';
import { motion, useInView } from 'framer-motion';

interface AnimatedSectionProps {
  children: React.ReactNode;
  className?: string;
  delay?: number;
}

export function AnimatedSection({ children, className, delay = 0 }: AnimatedSectionProps) {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, margin: '-80px' });

  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 32 }}
      animate={isInView ? { opacity: 1, y: 0 } : { opacity: 0, y: 32 }}
      transition={{ duration: 0.6, delay, ease: [0.21, 0.47, 0.32, 0.98] }}
      className={className}
    >
      {children}
    </motion.div>
  );
}

'use client';

import { useState } from 'react';
import { AnimatedSection } from './shared/AnimatedSection';
import { GitPullRequest, Lightbulb, Target, Layers } from 'lucide-react';

const tabs = [
  {
    id: 'decisions',
    label: 'Decisions',
    icon: GitPullRequest,
    color: 'text-blue-500',
    bgColor: 'bg-blue-500/10',
    borderColor: 'border-blue-500/20',
    activeColor: 'bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-500/30',
    card: {
      title: 'Migrate from REST to tRPC for type-safe API layer',
      situation: 'Dashboard API calls had no compile-time type checking. Typos in endpoint paths or response shapes caused runtime errors caught only during manual testing.',
      choice: 'Adopted tRPC with shared router types. Server and client share a single type definition — no codegen, no OpenAPI spec maintenance.',
      alternatives: ['GraphQL — too heavy for a local tool', 'OpenAPI codegen — adds a build step and drift risk'],
      tradeoffs: 'tRPC couples client to server framework. Acceptable for a monorepo where both are co-located.',
      revisit: 'If the API needs to serve non-TypeScript clients',
    },
  },
  {
    id: 'learnings',
    label: 'Learnings',
    icon: Lightbulb,
    color: 'text-amber-500',
    bgColor: 'bg-amber-500/10',
    borderColor: 'border-amber-500/20',
    activeColor: 'bg-amber-500/10 text-amber-600 dark:text-amber-400 border-amber-500/30',
    card: {
      title: 'better-sqlite3 WAL mode prevents SQLITE_BUSY during concurrent reads',
      symptom: 'Dashboard queries intermittently failed with SQLITE_BUSY when the CLI sync was running simultaneously.',
      rootCause: 'Default SQLite journal mode uses exclusive locks for writes, blocking all concurrent readers.',
      takeaway: 'Enable WAL mode (PRAGMA journal_mode=WAL) at connection time for any SQLite database with concurrent read/write access.',
      appliesWhen: 'Any Node.js app using better-sqlite3 where reads and writes happen simultaneously.',
    },
  },
  {
    id: 'promptQuality',
    label: 'Prompt Quality',
    icon: Target,
    color: 'text-emerald-500',
    bgColor: 'bg-emerald-500/10',
    borderColor: 'border-emerald-500/20',
    activeColor: 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/30',
    card: {
      score: 72,
      wastedTurns: 3,
      antiPatterns: ['Vague file references without paths', 'Changing requirements mid-implementation'],
      traits: [
        { name: 'late_context', severity: 'high', description: 'API key format requirement mentioned on turn 14, should have been in the initial prompt' },
        { name: 'good_structure', severity: 'positive', description: 'Clear separation between research and implementation phases' },
      ],
    },
  },
  {
    id: 'sessions',
    label: 'Session Types',
    icon: Layers,
    color: 'text-purple-500',
    bgColor: 'bg-purple-500/10',
    borderColor: 'border-purple-500/20',
    activeColor: 'bg-purple-500/10 text-purple-600 dark:text-purple-400 border-purple-500/30',
    card: {
      types: [
        { name: 'feature_build', count: 42, pct: 34, color: 'bg-blue-500' },
        { name: 'bug_hunt', count: 28, pct: 23, color: 'bg-red-500' },
        { name: 'deep_focus', count: 22, pct: 18, color: 'bg-purple-500' },
        { name: 'exploration', count: 15, pct: 12, color: 'bg-amber-500' },
        { name: 'refactor', count: 9, pct: 7, color: 'bg-emerald-500' },
        { name: 'quick_task', count: 7, pct: 6, color: 'bg-gray-500' },
      ],
    },
  },
] as const;

type TabId = (typeof tabs)[number]['id'];

function DecisionCard({ card }: { card: (typeof tabs)[0]['card'] }) {
  return (
    <div className="space-y-4">
      <h4 className="text-base font-semibold">{card.title}</h4>
      <div className="space-y-3 text-sm">
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Situation</span>
          <p className="mt-1 text-muted-foreground leading-relaxed">{card.situation}</p>
        </div>
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Choice</span>
          <p className="mt-1 text-muted-foreground leading-relaxed">{card.choice}</p>
        </div>
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Rejected alternatives</span>
          <ul className="mt-1 space-y-1">
            {card.alternatives.map((a) => (
              <li key={a} className="text-muted-foreground flex items-start gap-2">
                <span className="text-muted-foreground/40 mt-0.5">—</span>
                {a}
              </li>
            ))}
          </ul>
        </div>
        <div className="flex flex-wrap gap-3 pt-1">
          <div className="rounded-md bg-muted/50 px-3 py-1.5 text-xs text-muted-foreground">
            <span className="font-medium">Trade-off:</span> {card.tradeoffs}
          </div>
          <div className="rounded-md bg-muted/50 px-3 py-1.5 text-xs text-muted-foreground">
            <span className="font-medium">Revisit when:</span> {card.revisit}
          </div>
        </div>
      </div>
    </div>
  );
}

function LearningCard({ card }: { card: (typeof tabs)[1]['card'] }) {
  return (
    <div className="space-y-4">
      <h4 className="text-base font-semibold">{card.title}</h4>
      <div className="space-y-3 text-sm">
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Symptom</span>
          <p className="mt-1 text-muted-foreground leading-relaxed">{card.symptom}</p>
        </div>
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Root cause</span>
          <p className="mt-1 text-muted-foreground leading-relaxed">{card.rootCause}</p>
        </div>
        <div>
          <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Takeaway</span>
          <p className="mt-1 text-foreground font-medium leading-relaxed">{card.takeaway}</p>
        </div>
        <div className="rounded-md bg-muted/50 px-3 py-1.5 text-xs text-muted-foreground">
          <span className="font-medium">Applies when:</span> {card.appliesWhen}
        </div>
      </div>
    </div>
  );
}

function PromptQualityCard({ card }: { card: (typeof tabs)[2]['card'] }) {
  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <div className="text-4xl font-bold">{card.score}</div>
        <div>
          <div className="text-sm font-medium">Prompt Efficiency Score</div>
          <div className="text-xs text-muted-foreground">{card.wastedTurns} wasted turns detected</div>
        </div>
      </div>
      <div>
        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Anti-patterns detected</span>
        <ul className="mt-2 space-y-1.5">
          {card.antiPatterns.map((p) => (
            <li key={p} className="text-sm text-muted-foreground flex items-start gap-2">
              <span className="text-destructive mt-0.5">&#x2022;</span>
              {p}
            </li>
          ))}
        </ul>
      </div>
      <div>
        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Session traits</span>
        <div className="mt-2 space-y-2">
          {card.traits.map((t) => (
            <div key={t.name} className="rounded-md bg-muted/50 px-3 py-2 text-xs">
              <div className="flex items-center gap-2 mb-1">
                <span className="font-mono font-medium">{t.name}</span>
                <span className={`inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium ${
                  t.severity === 'positive'
                    ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400'
                    : 'bg-destructive/10 text-destructive'
                }`}>
                  {t.severity}
                </span>
              </div>
              <p className="text-muted-foreground">{t.description}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function SessionTypesCard({ card }: { card: (typeof tabs)[3]['card'] }) {
  return (
    <div className="space-y-4">
      <div>
        <div className="text-sm font-medium mb-3">LLM classifies each session into one of 7 types based on conversation content</div>
        {/* Stacked bar */}
        <div className="flex rounded-full h-3 overflow-hidden mb-4">
          {card.types.map((t) => (
            <div key={t.name} className={`${t.color}/70`} style={{ width: `${t.pct}%` }} />
          ))}
        </div>
      </div>
      <div className="grid grid-cols-2 gap-2">
        {card.types.map((t) => (
          <div key={t.name} className="flex items-center gap-2.5 rounded-md bg-muted/50 px-3 py-2">
            <div className={`h-2.5 w-2.5 rounded-full ${t.color}/70 shrink-0`} />
            <div className="min-w-0">
              <div className="text-xs font-mono font-medium truncate">{t.name}</div>
              <div className="text-[10px] text-muted-foreground">{t.count} sessions ({t.pct}%)</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export function ProofSection() {
  const [activeTab, setActiveTab] = useState<TabId>('decisions');
  const activeTabData = tabs.find((t) => t.id === activeTab)!;

  return (
    <section id="proof" className="py-14 lg:py-20 bg-gradient-to-b from-transparent via-accent/30 to-transparent">
      <div className="max-w-4xl mx-auto px-6">
        <AnimatedSection>
          <div className="text-center mb-10">
            <h2 className="text-3xl sm:text-4xl font-bold tracking-tight">
              What the LLM extracts from your sessions
            </h2>
            <p className="mt-3 text-lg text-muted-foreground max-w-2xl mx-auto">
              Every session is analyzed into structured, searchable knowledge — not just chat logs.
            </p>
          </div>
        </AnimatedSection>

        <AnimatedSection delay={0.1}>
          {/* Tab bar */}
          <div className="flex flex-wrap justify-center gap-2 mb-6">
            {tabs.map((tab) => {
              const Icon = tab.icon;
              const isActive = tab.id === activeTab;
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`inline-flex items-center gap-1.5 rounded-full border px-3.5 py-1.5 text-sm font-medium transition-all ${
                    isActive
                      ? tab.activeColor
                      : 'border-border/50 bg-card/50 text-muted-foreground hover:bg-card/80 hover:border-border'
                  }`}
                >
                  <Icon className="h-3.5 w-3.5" />
                  {tab.label}
                </button>
              );
            })}
          </div>

          {/* Card */}
          <div className="rounded-xl border border-border/40 bg-card/70 backdrop-blur-sm shadow-lg shadow-primary/5 p-6 sm:p-8">
            <div className="flex items-center gap-2 mb-4">
              <div className={`h-7 w-7 rounded-md ${activeTabData.bgColor} ${activeTabData.borderColor} border flex items-center justify-center`}>
                <activeTabData.icon className={`h-3.5 w-3.5 ${activeTabData.color}`} />
              </div>
              <span className={`text-xs font-medium ${activeTabData.color}`}>{activeTabData.label}</span>
            </div>
            {activeTab === 'decisions' && <DecisionCard card={tabs[0].card} />}
            {activeTab === 'learnings' && <LearningCard card={tabs[1].card} />}
            {activeTab === 'promptQuality' && <PromptQualityCard card={tabs[2].card} />}
            {activeTab === 'sessions' && <SessionTypesCard card={tabs[3].card} />}
          </div>
        </AnimatedSection>
      </div>
    </section>
  );
}

