 7→/**
 8→ * A structured content block for LLM messages.
 9→ * Used to enable prompt caching (Anthropic ephemeral cache) and structured multi-part messages.
10→ * The `cache_control` field instructs Anthropic to cache everything up to and including this block.
11→ */
12→export interface ContentBlock {
13→  type: 'text';
14→  text: string;
15→  cache_control?: { type: 'ephemeral' };
16→}
17→
18→/**
19→ * Flatten a ContentBlock array to a plain string by joining all block texts.
20→ * Used by non-Anthropic providers (OpenAI, Gemini, Ollama) that don't support content blocks natively.
21→ * If content is already a string, returns it unchanged.
22→ */
23→export function flattenContent(content: string | ContentBlock[]): string {
24→  if (typeof content === 'string') return content;
25→  return content.map(b => b.text).join('');
26→}
