  1→// LLM response parsing utilities.
  2→// Extracted from prompts.ts — handles JSON extraction, repair, and validation.
  3→
  4→import { jsonrepair } from 'jsonrepair';
  5→import type { AnalysisResponse, ParseError, ParseResult, PromptQualityResponse, PromptQualityDimensionScores } from './prompt-types.js';
  6→
  7→function buildResponsePreview(text: string, head = 200, tail = 200): string {
  8→  if (text.length <= head + tail + 20) return text;
  9→  return `${text.slice(0, head)}\n...[${text.length - head - tail} chars omitted]...\n${text.slice(-tail)}`;
 10→}
 11→
 12→export function extractJsonPayload(response: string): string | null {
 13→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
 14→  if (tagged?.[1]) return tagged[1].trim();
 15→  const jsonMatch = response.match(/\{[\s\S]*\}/);
 16→  return jsonMatch ? jsonMatch[0] : null;
 17→}
 18→
 19→/**
 20→ * Parse the LLM response into structured insights.
 21→ */
 22→export function parseAnalysisResponse(response: string): ParseResult<AnalysisResponse> {
 23→  const response_length = response.length;
 24→
 25→  const preview = buildResponsePreview(response);
 26→
 27→  const jsonPayload = extractJsonPayload(response);
 28→  if (!jsonPayload) {
 29→    console.error('No JSON found in analysis response');
 30→    return {
 31→      success: false,
 32→      error: { error_type: 'no_json_found', error_message: 'No JSON found in analysis response', response_length, response_preview: preview },
 33→    };
 34→  }
 35→
 36→  let parsed: AnalysisResponse;
 37→  try {
 38→    parsed = JSON.parse(jsonPayload) as AnalysisResponse;
 39→  } catch {
 40→    // Attempt repair — handles trailing commas, unclosed braces, truncated output
 41→    try {
 42→      parsed = JSON.parse(jsonrepair(jsonPayload)) as AnalysisResponse;
 43→    } catch (err) {
 44→      const msg = err instanceof Error ? err.message : String(err);
 45→      console.error('Failed to parse analysis response (after jsonrepair):', err);
 46→      return {
 47→        success: false,
 48→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
 49→      };
 50→    }
 51→  }
 52→
 53→  if (!parsed.summary || typeof parsed.summary.title !== 'string') {
 54→    console.error('Invalid analysis response structure');
 55→    return {
 56→      success: false,
 57→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid summary field', response_length, response_preview: preview },
 58→    };
 59→  }
 60→
 61→  parsed.decisions = parsed.decisions || [];
 62→  parsed.learnings = parsed.learnings || [];
 63→
 64→  // Observability: warn when LLM still uses "tooling-limitation".
 65→  // Monitors whether FRICTION_CLASSIFICATION_GUIDANCE is working.
 66→  // Remove after confirming classification quality over ~20 new sessions.
 67→  if (parsed.facets?.friction_points?.some(fp => fp.category === 'tooling-limitation')) {
 68→    console.warn('[friction-monitor] LLM classified friction as "tooling-limitation" — verify this is a genuine tool limitation, not an agent/rate-limit/approach issue');
 69→  }
 70→
 71→  // Observability: warn when LLM returns effective_pattern without category or driver field,
 72→  // or with an unrecognized driver value.
 73→  // Catches models that ignore the classification instructions (especially smaller Ollama models).
 74→  // Remove after confirming classification quality over ~20 new sessions.
 75→  if (parsed.facets?.effective_patterns?.some(ep => !ep.category)) {
 76→    console.warn('[pattern-monitor] LLM returned effective_pattern without category field');
 77→  }
 78→  if (parsed.facets?.effective_patterns?.some(ep => !ep.driver)) {
 79→    console.warn('[pattern-monitor] LLM returned effective_pattern without driver field — driver classification may be incomplete');
 80→  }
 81→  const VALID_DRIVERS = new Set(['user-driven', 'ai-driven', 'collaborative']);
 82→  if (parsed.facets?.effective_patterns?.some(ep => ep.driver && !VALID_DRIVERS.has(ep.driver))) {
 83→    console.warn('[pattern-monitor] LLM returned unexpected driver value — check classification quality');
 84→  }
 85→
 86→  // Observability: warn when LLM omits _reasoning CoT scratchpad fields.
 87→  // These fields force the model to work through the attribution/driver decision trees
 88→  // before committing to values. Missing _reasoning suggests the model skipped the CoT step.
 89→  // Remove after confirming CoT compliance over ~20 new sessions.
 90→  if (parsed.facets?.friction_points?.some(fp => !fp._reasoning)) {
 91→    console.warn('[cot-monitor] LLM returned friction_point without _reasoning — classification may lack decision-tree rigor');
 92→  }
 93→  if (parsed.facets?.effective_patterns?.some(ep => !ep._reasoning)) {
 94→    console.warn('[cot-monitor] LLM returned effective_pattern without _reasoning — classification may lack decision-tree rigor');
 95→  }
 96→
 97→  return { success: true, data: parsed };
 98→}
 99→
100→export function parsePromptQualityResponse(response: string): ParseResult<PromptQualityResponse> {
101→  const response_length = response.length;
102→  const preview = buildResponsePreview(response);
103→
104→  const jsonPayload = extractJsonPayload(response);
105→  if (!jsonPayload) {
106→    console.error('No JSON found in prompt quality response');
107→    return {
108→      success: false,
109→      error: { error_type: 'no_json_found', error_message: 'No JSON found in prompt quality response', response_length, response_preview: preview },
110→    };
111→  }
112→
113→  let parsed: PromptQualityResponse;
114→  try {
115→    parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
116→  } catch {
117→    try {
118→      parsed = JSON.parse(jsonrepair(jsonPayload)) as PromptQualityResponse;
119→    } catch (err) {
120→      const msg = err instanceof Error ? err.message : String(err);
121→      console.error('Failed to parse prompt quality response (after jsonrepair):', msg);
122→      return {
123→        success: false,
124→        error: { error_type: 'json_parse_error', error_message: msg, response_length, response_preview: preview },
125→      };
126→    }
127→  }
128→
129→  if (typeof parsed.efficiency_score !== 'number') {
130→    console.error('Invalid prompt quality response: missing efficiency_score');
131→    return {
132→      success: false,
133→      error: { error_type: 'invalid_structure', error_message: 'Missing or invalid efficiency_score field', response_length, response_preview: preview },
134→    };
135→  }
136→
137→  // Clamp and default
138→  parsed.efficiency_score = Math.max(0, Math.min(100, Math.round(parsed.efficiency_score)));
139→  parsed.message_overhead = parsed.message_overhead ?? 0;
140→  parsed.assessment = parsed.assessment || '';
141→  parsed.takeaways = parsed.takeaways || [];
142→  parsed.findings = parsed.findings || [];
143→  parsed.dimension_scores = parsed.dimension_scores || {
144→    context_provision: 50,
145→    request_specificity: 50,
146→    scope_management: 50,
147→    information_timing: 50,
148→    correction_quality: 50,
149→  };
